import { toServerItemCommunityCommentList, } from '../../../../models/server/items/community/comments/list.js';
import { extractString } from '../../../../utils/extract.js';
import { handleError } from '../../../error.js';
export const createServerItemCommunityCommentListRouteHandler = (sonolus, group) => async ({ req, res, localize, ctx }) => {
    if (!group.community.comment.listHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const response = await group.community.comment.listHandler({
        ...ctx,
        itemName,
        page: +(req.query.page ?? '') || 0,
        cursor: extractString(req.query.cursor),
    });
    if (handleError(response, res, localize))
        return;
    res.json(toServerItemCommunityCommentList(sonolus, localize, response, group.community.comment.actions));
};
